import React from 'react';
import CodeChefStats from './CodeChefStats';

export default function EnhancedCodeChefStats() {
  return (
    <div className="space-y-4">
      <div className="bg-amber-500 text-white p-4 rounded-xl shadow-lg mb-6">
        <h2 className="text-xl font-bold flex items-center gap-2">
          ✨ Enhanced CodeChef Insights (Beta)
        </h2>
        <p className="text-sm opacity-80">Advanced scraping and visual metrics are being integrated.</p>
      </div>
      <CodeChefStats />
    </div>
  );
}
